// Prepara el email en RFC 2822 base64 para cada una de las 3 marcas
const brand = $input.item.json;
const destEmail = process.env.DEMO_EMAIL_DESTINO || 'briyidcatalinacruzostos@gmail.com';

const subject = `Addi Marketplace: oportunidad para ${brand.category}`;
const body = `Hola,

Notamos que ${brand.brand_id} procesó COP ${brand.gmv_cop_millions_12m.toLocaleString('es-CO')} MM
con Addi BNPL en los últimos 12 meses, con un crecimiento del
${Math.round(brand.gmv_90d_to_12m_ratio * 100)}% en el último trimestre.

Eso nos dice que tus clientes ya confían en financiamiento Addi para
comprar en tu tienda. La pregunta natural es: ¿por qué no darles esa
misma opción directamente desde el Marketplace de Addi, donde ya hay
miles de compradores activos buscando productos de ${brand.category}?

Con un score de ${brand.final_score}/100 en tu categoría, la oportunidad
de ser de los primeros en ${brand.category} dentro del Marketplace es real y concreta.

¿Tienes 20 minutos esta semana para explorar si tiene sentido?

Saludos,
Equipo GTM Addi Marketplace`;

// Construir mensaje MIME RFC 2822
const mimeMessage = `From: me\r\nTo: ${destEmail}\r\nSubject: ${subject}\r\nContent-Type: text/plain; charset=utf-8\r\n\r\n${body}`;

// Convertir a base64
const base64Message = Buffer.from(mimeMessage).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');

return {
  json: {
    brand_id: brand.brand_id,
    category: brand.category,
    gmv_cop_millions_12m: brand.gmv_cop_millions_12m,
    subject: subject,
    body: body,
    raw: base64Message,
    to: destEmail
  }
};

// Log del email enviado
const result = $input.item.json;
console.log(`✓ Email enviado para ${result.json.brand_id}`);
console.log(`  Message ID: ${result.json.id}`);
console.log(`  Para: ${result.json.to}`);

return {
  json: {
    brand_id: result.json.brand_id,
    category: result.json.category,
    message_id: result.json.id,
    to: result.json.to,
    timestamp: new Date().toISOString()
  }
};
